618 ConstraintInfo::getConstraint(CmpInst::Predicate Pred, Value *Op0, Value *Op1,
619                               SmallVectorImpl<Value *> &NewVariables) const {
620   assert(NewVariables.empty() && "NewVariables must be empty when passed in");
