1423     return true;
1424   };
1425 
1426   if (auto ImpliedCondition =
1427           checkCondition(Cmp->getPredicate(), Cmp->getOperand(0),
1428                          Cmp->getOperand(1), Cmp, Info))
1429     return ReplaceCmpWithConstant(Cmp, *ImpliedCondition);
