1614 static bool replaceSubOverflowUses(IntrinsicInst *II, Value *A, Value *B,
1615                                    SmallVectorImpl<Instruction *> &ToRemove) {
1616   bool Changed = false;
1617   IRBuilder<> Builder(II->getParent(), II->getIterator());
